import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface SubjectBreakdown {
  subject: string;
  time: number;
}

interface WeeklyComparison {
  day: string;
  hours: number;
}

interface StudyData {
  todayStudyHours: number;
  subjectBreakdown: SubjectBreakdown[];
  weeklyComparison: WeeklyComparison[];
}

export default function Widget() {
  const studyData = response.data as StudyData;
  const { todayStudyHours, subjectBreakdown, weeklyComparison } = studyData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#4A90E2' }}>
              Study Summary
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Today’s Study Hours
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#F5A623' }}>
              {todayStudyHours} hrs
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Weekly Study Hours
            </Typography>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: weeklyComparison.map(d => d.hours),
                  color: '#4A90E2',
                  label: 'Hours',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: weeklyComparison.map(d => d.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'hours' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="hours"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Subject Breakdown
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {subjectBreakdown.map((subject, index) => (
                <Typography
                  key={index}
                  variant="body2"
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#E0E7FF', borderRadius: 1 }}
                >
                  {subject.subject}: {subject.time} hrs
                </Typography>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
